17	package org.springframework.boot.context.properties.bind;
18	
19	import java.lang.annotation.Annotation;
20	import java.lang.reflect.Array;
21	import java.util.Arrays;
22	import java.util.EnumSet;
23	import java.util.List;
24	import java.util.Map;
25	import java.util.Set;
26	import java.util.function.Supplier;
27	
28	import org.jspecify.annotations.Nullable;
29	
30	import org.springframework.boot.context.properties.source.ConfigurationProperty;
31	import org.springframework.core.ResolvableType;
32	import org.springframework.core.style.ToStringCreator;
33	import org.springframework.util.Assert;
34	import org.springframework.util.ObjectUtils;
35	
36	/**
37	 * Source that can be bound by a {@link Binder}.
38	 *
39	 * @param <T> the source type
40	 * @author Phillip Webb
41	 * @author Madhura Bhave
42	 * @since 2.0.0
43	 * @see Bindable#of(Class)
44	 * @see Bindable#of(ResolvableType)
45	 */
46	public final class Bindable<T> {
47	
48		private static final Annotation[] NO_ANNOTATIONS = {};
49	
50		private static final EnumSet<BindRestriction> NO_BIND_RESTRICTIONS = EnumSet.noneOf(BindRestriction.class);
51	
52		private final ResolvableType type;
53	
54		private final ResolvableType boxedType;
55	
56		private final @Nullable Supplier<T> value;
57	
58		private final Annotation[] annotations;
59	
60		private final EnumSet<BindRestriction> bindRestrictions;
61	
62		private final @Nullable BindMethod bindMethod;
63	
64		private Bindable(ResolvableType type, ResolvableType boxedType, @Nullable Supplier<T> value,
65				Annotation[] annotations, EnumSet<BindRestriction> bindRestrictions, @Nullable BindMethod bindMethod) {
66			this.type = type;
67			this.boxedType = boxedType;
68			this.value = value;
69			this.annotations = annotations;
70			this.bindRestrictions = bindRestrictions;
71			this.bindMethod = bindMethod;
72		}
73	
74		/**
75		 * Return the type of the item to bind.
76		 * @return the type being bound
77		 */
78		public ResolvableType getType() {
79			return this.type;
80		}
81	
82		/**
83		 * Return the boxed type of the item to bind.
84		 * @return the boxed type for the item being bound
85		 */
86		public ResolvableType getBoxedType() {
87			return this.boxedType;
88		}
89	
90		/**
91		 * Return a supplier that provides the object value or {@code null}.
92		 * @return the value or {@code null}
93		 */
94		public @Nullable Supplier<T> getValue() {
95			return this.value;
96		}
97	
98		/**
99		 * Return any associated annotations that could affect binding.
100		 * @return the associated annotations
101		 */
102		public Annotation[] getAnnotations() {
103			return this.annotations;
104		}
105	
106		/**
107		 * Return a single associated annotations that could affect binding.
108		 * @param <A> the annotation type
109		 * @param type annotation type
110		 * @return the associated annotation or {@code null}
111		 */
112		@SuppressWarnings("unchecked")
113		public <A extends Annotation> @Nullable A getAnnotation(Class<A> type) {
114			for (Annotation annotation : this.annotations) {
115				if (type.isInstance(annotation)) {
116					return (A) annotation;
117				}
118			}
119			return null;
120		}
121	
122		/**
123		 * Returns {@code true} if the specified bind restriction has been added.
124		 * @param bindRestriction the bind restriction to check
125		 * @return if the bind restriction has been added
126		 * @since 2.5.0
127		 */
128		public boolean hasBindRestriction(BindRestriction bindRestriction) {
129			return this.bindRestrictions.contains(bindRestriction);
130		}
131	
132		/**
133		 * Returns the {@link BindMethod method} to be used to bind this bindable, or
134		 * {@code null} if no specific binding method is required.
135		 * @return the bind method or {@code null}
136		 * @since 3.0.8
137		 */
138		public @Nullable BindMethod getBindMethod() {
139			return this.bindMethod;
140		}
141	
142		@Override
143		public boolean equals(Object obj) {
144			if (this == obj) {
145				return true;
146			}
147			if (obj == null || getClass() != obj.getClass()) {
148				return false;
149			}
150			Bindable<?> other = (Bindable<?>) obj;
151			boolean result = true;
152			result = result && nullSafeEquals(this.type.resolve(), other.type.resolve());
153			result = result && nullSafeEquals(this.annotations, other.annotations);
154			result = result && nullSafeEquals(this.bindRestrictions, other.bindRestrictions);
155			result = result && nullSafeEquals(this.bindMethod, other.bindMethod);
156			return result;
157		}
158	
159		@Override
160		public int hashCode() {
161			return ObjectUtils.nullSafeHash(this.type, this.annotations, this.bindRestrictions, this.bindMethod);
162		}
163	
164		@Override
165		public String toString() {
166			ToStringCreator creator = new ToStringCreator(this);
167			creator.append("type", this.type);
168			creator.append("value", (this.value != null) ? "provided" : "none");
169			creator.append("annotations", this.annotations);
170			creator.append("bindMethod", this.bindMethod);
171			return creator.toString();
172		}
173	
174		private boolean nullSafeEquals(@Nullable Object o1, @Nullable Object o2) {
175			return ObjectUtils.nullSafeEquals(o1, o2);
176		}
177	
178		/**
179		 * Create an updated {@link Bindable} instance with the specified annotations.
180		 * @param annotations the annotations
181		 * @return an updated {@link Bindable}
182		 */
183		public Bindable<T> withAnnotations(Annotation @Nullable ... annotations) {
184			return new Bindable<>(this.type, this.boxedType, this.value,
185					(annotations != null) ? annotations : NO_ANNOTATIONS, NO_BIND_RESTRICTIONS, this.bindMethod);
186		}
187	
188		/**
189		 * Create an updated {@link Bindable} instance with an existing value. Implies that
190		 * Java Bean binding will be used.
191		 * @param existingValue the existing value
192		 * @return an updated {@link Bindable}
193		 */
194		public Bindable<T> withExistingValue(@Nullable T existingValue) {
195			Assert.isTrue(existingValue == null || this.type.isArray() || boxedTypeIsInstanceOf(existingValue),
196					() -> "'existingValue' must be an instance of " + this.type);
197			Assert.state(this.bindMethod != BindMethod.VALUE_OBJECT,
198					() -> "An existing value cannot be provided when binding as a value object");
199			Supplier<T> value = (existingValue != null) ? () -> existingValue : null;
200			return new Bindable<>(this.type, this.boxedType, value, this.annotations, this.bindRestrictions,
201					BindMethod.JAVA_BEAN);
202		}
203	
204		private boolean boxedTypeIsInstanceOf(T existingValue) {
205			Class<?> resolved = this.boxedType.resolve();
206			return resolved != null && resolved.isInstance(existingValue);
207		}
208	
209		/**
210		 * Create an updated {@link Bindable} instance with a value supplier.
211		 * @param suppliedValue the supplier for the value
212		 * @return an updated {@link Bindable}
213		 */
214		public Bindable<T> withSuppliedValue(@Nullable Supplier<T> suppliedValue) {
215			return new Bindable<>(this.type, this.boxedType, suppliedValue, this.annotations, this.bindRestrictions,
216					this.bindMethod);
217		}
218	
219		/**
220		 * Create an updated {@link Bindable} instance with additional bind restrictions.
221		 * @param additionalRestrictions any additional restrictions to apply
222		 * @return an updated {@link Bindable}
223		 * @since 2.5.0
224		 */
225		public Bindable<T> withBindRestrictions(BindRestriction... additionalRestrictions) {
226			EnumSet<BindRestriction> bindRestrictions = EnumSet.copyOf(this.bindRestrictions);
227			bindRestrictions.addAll(Arrays.asList(additionalRestrictions));
228			return new Bindable<>(this.type, this.boxedType, this.value, this.annotations, bindRestrictions,
229					this.bindMethod);
230		}
231	
232		/**
233		 * Create an updated {@link Bindable} instance with a specific bind method. To use
234		 * {@link BindMethod#VALUE_OBJECT value object binding}, the current instance must not
235		 * have an existing or supplied value.
236		 * @param bindMethod the method to use to bind the bindable
237		 * @return an updated {@link Bindable}
238		 * @since 3.0.8
239		 */
240		public Bindable<T> withBindMethod(@Nullable BindMethod bindMethod) {
241			Assert.state(bindMethod != BindMethod.VALUE_OBJECT || this.value == null,
242					() -> "Value object binding cannot be used with an existing or supplied value");
243			return new Bindable<>(this.type, this.boxedType, this.value, this.annotations, this.bindRestrictions,
244					bindMethod);
245		}
246	
247		/**
248		 * Create a new {@link Bindable} of the type of the specified instance with an
249		 * existing value equal to the instance.
250		 * @param <T> the source type
251		 * @param instance the instance (must not be {@code null})
252		 * @return a {@link Bindable} instance
253		 * @see #of(ResolvableType)
254		 * @see #withExistingValue(Object)
255		 */
256		@SuppressWarnings("unchecked")
257		public static <T> Bindable<T> ofInstance(T instance) {
258			Assert.notNull(instance, "'instance' must not be null");
259			Class<T> type = (Class<T>) instance.getClass();
260			return of(type).withExistingValue(instance);
261		}
262	
263		/**
264		 * Create a new {@link Bindable} of the specified type.
265		 * @param <T> the source type
266		 * @param type the type (must not be {@code null})
267		 * @return a {@link Bindable} instance
268		 * @see #of(ResolvableType)
269		 */
270		public static <T> Bindable<T> of(Class<T> type) {
271			Assert.notNull(type, "'type' must not be null");
272			return of(ResolvableType.forClass(type));
273		}
274	
275		/**
276		 * Create a new {@link Bindable} {@link List} of the specified element type.
277		 * @param <E> the element type
278		 * @param elementType the list element type
279		 * @return a {@link Bindable} instance
280		 */
281		public static <E> Bindable<List<E>> listOf(Class<E> elementType) {
282			return of(ResolvableType.forClassWithGenerics(List.class, elementType));
283		}
284	
285		/**
286		 * Create a new {@link Bindable} {@link Set} of the specified element type.
287		 * @param <E> the element type
288		 * @param elementType the set element type
289		 * @return a {@link Bindable} instance
290		 */
291		public static <E> Bindable<Set<E>> setOf(Class<E> elementType) {
292			return of(ResolvableType.forClassWithGenerics(Set.class, elementType));
293		}
294	
295		/**
296		 * Create a new {@link Bindable} {@link Map} of the specified key and value type.
297		 * @param <K> the key type
298		 * @param <V> the value type
299		 * @param keyType the map key type
300		 * @param valueType the map value type
301		 * @return a {@link Bindable} instance
302		 */
303		public static <K, V> Bindable<Map<K, V>> mapOf(Class<K> keyType, Class<V> valueType) {
304			return of(ResolvableType.forClassWithGenerics(Map.class, keyType, valueType));
305		}
306	
307		/**
308		 * Create a new {@link Bindable} of the specified type.
309		 * @param <T> the source type
310		 * @param type the type (must not be {@code null})
311		 * @return a {@link Bindable} instance
312		 * @see #of(Class)
313		 */
314		public static <T> Bindable<T> of(ResolvableType type) {
315			Assert.notNull(type, "'type' must not be null");
316			ResolvableType boxedType = box(type);
317			return new Bindable<>(type, boxedType, null, NO_ANNOTATIONS, NO_BIND_RESTRICTIONS, null);
318		}
319	
320		private static ResolvableType box(ResolvableType type) {
321			Class<?> resolved = type.resolve();
322			if (resolved != null && resolved.isPrimitive()) {
323				Object array = Array.newInstance(resolved, 1);
324				Class<?> wrapperType = Array.get(array, 0).getClass();
325				return ResolvableType.forClass(wrapperType);
326			}
327			if (resolved != null && resolved.isArray()) {
328				return ResolvableType.forArrayComponent(box(type.getComponentType()));
329			}
330			return type;
331		}
332	
333		/**
334		 * Restrictions that can be applied when binding values.
335		 *
336		 * @since 2.5.0
337		 */
338		public enum BindRestriction {
339	
340			/**
341			 * Do not bind direct {@link ConfigurationProperty} matches.
342			 */
343			NO_DIRECT_PROPERTY
344	
345		}
346	
347	}
