186		/**
187		 * Create a new {@link Binder} instance for the specified sources.
188		 * @param sources the sources used for binding
189		 * @param placeholdersResolver strategy to resolve any property placeholders
190		 * @param conversionServices the conversion services to convert values (or
191		 * {@code null} to use {@link ApplicationConversionService})
192		 * @param propertyEditorInitializer initializer used to configure the property editors
193		 * that can convert values (or {@code null} if no initialization is required). Often
194		 * used to call {@link ConfigurableListableBeanFactory#copyRegisteredEditorsTo}.
195		 * @param defaultBindHandler the default bind handler to use if none is specified when
196		 * binding
197		 * @param constructorProvider the constructor provider which provides the bind
198		 * constructor to use when binding
199		 * @since 2.5.0
200		 */
201		public Binder(Iterable<ConfigurationPropertySource> sources, @Nullable PlaceholdersResolver placeholdersResolver,
202				@Nullable List<ConversionService> conversionServices,
203				@Nullable Consumer<PropertyEditorRegistry> propertyEditorInitializer,
204				@Nullable BindHandler defaultBindHandler, @Nullable BindConstructorProvider constructorProvider) {
205			Assert.notNull(sources, "'sources' must not be null");
206			for (ConfigurationPropertySource source : sources) {
207				Assert.notNull(source, "'sources' must not contain null elements");
208			}
209			this.sources = sources;
210			this.configurationPropertyCaching = ConfigurationPropertyCaching.get(sources);
211			this.placeholdersResolver = (placeholdersResolver != null) ? placeholdersResolver : PlaceholdersResolver.NONE;
212			this.bindConverter = BindConverter.get(conversionServices, propertyEditorInitializer);
213			this.defaultBindHandler = (defaultBindHandler != null) ? defaultBindHandler : BindHandler.DEFAULT;
214			if (constructorProvider == null) {
215				constructorProvider = BindConstructorProvider.DEFAULT;
216			}
217			ValueObjectBinder valueObjectBinder = new ValueObjectBinder(constructorProvider);
218			JavaBeanBinder javaBeanBinder = JavaBeanBinder.INSTANCE;
219			Map<@Nullable BindMethod, List<DataObjectBinder>> dataObjectBinders = new HashMap<>();
220			dataObjectBinders.put(BindMethod.VALUE_OBJECT, List.of(valueObjectBinder));
221			dataObjectBinders.put(BindMethod.JAVA_BEAN, List.of(javaBeanBinder));
222			dataObjectBinders.put(null, List.of(valueObjectBinder, javaBeanBinder));
223			this.dataObjectBinders = Collections.unmodifiableMap(dataObjectBinders);
224		}
